namespace optiling {

static ge::graphStatus TilingFunc(gert::TilingContext *context)
{
    ConvStandard3dSquareInputAsymmetricKernelCustomTilingData tiling;

    const auto *xShape = context->GetInputShape(0);
    const auto *wShape = context->GetInputShape(1);

    // Input layout: [N, C_in, W, H, D]
    // Weight layout: [C_out, C_in, K_w, K_h, K_d]
    const uint32_t n   = static_cast<uint32_t>(xShape->GetOriginShape().GetDim(0));
    const uint32_t cin = static_cast<uint32_t>(xShape->GetOriginShape().GetDim(1));
    const uint32_t w   = static_cast<uint32_t>(xShape->GetOriginShape().GetDim(2));
    const uint32_t h   = static_cast<uint32_t>(xShape->GetOriginShape().GetDim(3));
    const uint32_t d   = static_cast<uint32_t>(xShape->GetOriginShape().GetDim(4));

    const uint32_t cout = static_cast<uint32_t>(wShape->GetOriginShape().GetDim(0));
    const uint32_t kw   = static_cast<uint32_t>(wShape->GetOriginShape().GetDim(2));
    const uint32_t kh   = static_cast<uint32_t>(wShape->GetOriginShape().GetDim(3));
    const uint32_t kd   = static_cast<uint32_t>(wShape->GetOriginShape().GetDim(4));

    // stride=(1,1,1), padding=(0,0,0), dilation=(1,1,1)
    const uint32_t outw = (w >= kw) ? (w - kw + 1u) : 0u;
    const uint32_t outh = (h >= kh) ? (h - kh + 1u) : 0u;
    const uint32_t outd = (d >= kd) ? (d - kd + 1u) : 0u;

    // Block parallelism on output channels
    uint32_t blockDim = cout;
    if (blockDim < 8u) blockDim = 8u;
    if (blockDim > 24u) blockDim = 24u;
    if (blockDim > cout) blockDim = cout == 0 ? 1u : cout;
    context->SetBlockDim(blockDim);

    const uint32_t tileCout = CeilDiv(cout, blockDim == 0 ? 1u : blockDim);

    tiling.set_n(n);
    tiling.set_cin(cin);
    tiling.set_cout(cout);
    tiling.set_w(w);
    tiling.set_h(h);
    tiling.set_d(d);
    tiling.set_kw(kw);
    tiling.set_kh(kh);
    tiling.set_kd(kd);
    tiling.set_outw(outw);
    tiling.set_outh(outh);
    tiling.set_outd(outd);
    tiling.set_tileCout(tileCout);
    tiling.set_blockDim(blockDim);

    tiling.SaveToBuffer(context->GetRawTilingData()->GetData(),
                        context->GetRawTilingData()->GetCapacity());
    context->GetRawTilingData()->SetDataSize(tiling.GetDataSize());

    size_t *workspaceSizes = context->GetWorkspaceSizes(1);
    workspaceSizes[0] = 0;
    return ge::GRAPH_SUCCESS;
}

